import React, { useState, useEffect } from "react";
import {
    SectionWrapper,
    Wrapper,
} from "../../components/Styles/RegisterStyles";
import axios from "axios";
import DataTable from "react-data-table-component";
import { Link } from "react-router-dom";
import { FaEye, FaEllipsisV } from "react-icons/fa";
import SideBar from '../../components/Investor/social/SideBar';
import TopBar from '../../components/Investor/social/TopBar';
import { DataRoomSection } from "../../components/Styles/DataRoomStyle.js";
import { useNavigate } from 'react-router-dom';
import CapitalRoundViewCompanyInvite from "../../components/Investor/popup/CapitalRoundViewCompanyInvite.jsx"
import ChatMessageModal from "../../components/social/company/ChatMessageModal.jsx";
import DangerAlertPopup from "../../components/Admin/DangerAlertPopup.jsx";
import { API_BASE_URL } from "../../config/config.js";
function CompanyInvitationList() {
    const navigate = useNavigate();
    const [popupOpen, setPopupOpen] = useState(false);
    const [selectedIds, setSelectedIds] = useState({ id: null, roundrecord_id: null });
    const [open, setOpen] = useState(false);
    const [messagesuccessError, setmessagesuccessError] = useState("");
    const [errr, seterrr] = useState(false);
    const [records, setRecords] = useState([]);
    const [ClientIP, setClientIP] = useState("");
    const [CountryName, setCountryName] = useState("");
    const customStyles = {
        table: {
            style: {
                overflow: "visible !important",
                minWidth: "100%",
                boxShadow: "0px 3px 12px rgb(0 0 0 / 16%)",
                borderRadius: "12px",
            },
        },
        headCells: {
            style: {
                backgroundColor: "#efefef !important",
                fontWeight: "600",
                fontSize: "0.9rem",
                color: "#000 !important",
                whiteSpace: "nowrap",
            },
        },
        cells: {
            style: {
                whiteSpace: "nowrap",
                textOverflow: "ellipsis",
                backgroundColor: "#fff !important",
            },
        },
        rows: {
            style: {
                fontSize: "0.8rem",
                fontWeight: "500",
                "&:hover": {
                    backgroundColor: "#e8f0fe",
                },
            },
            stripedStyle: {
                backgroundColor: "#f4f6f8",
            },
        },
        pagination: {
            style: {
                backgroundColor: "#fafafa",
                padding: "12px 16px",
            },
        },
    };
    var apiURL = API_BASE_URL + "api/user/investor/";
    var apiURLround = API_BASE_URL + "api/user/investorround/";

    const storedUsername = localStorage.getItem("InvestorData");
    const userLogin = JSON.parse(storedUsername);
    const access_token = userLogin?.access_token;
    const [searchText, setSearchText] = useState("");
    const [isCollapsed, setIsCollapsed] = useState(false);
    document.title = "Incoming Invitations - Investor";
    useEffect(() => {
        const getIP = async () => {
            try {
                const res = await fetch("https://ipapi.co/json/");
                const data = await res.json();

                setClientIP(data.ip); // Save this to state
                setCountryName(data.country_name);
            } catch (error) {
                console.error("Failed to fetch IP", error);
            }
        };

        getIP();
    }, []);
    useEffect(() => {
        getInvitaionCompany();
    }, []);
    const getInvitaionCompany = async () => {
        let formData = {
            investor_id: userLogin.id,
        };

        try {
            const res = await axios.post(apiURL + "getInvitaionCompany", formData, {
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",
                    'Authorization': `Bearer ${access_token}`,
                },
            });
            console.log(res.data.data);
            setRecords(res.data.data);
        } catch (err) { }
    };
    const handlejoinCompany = async (userid, company_id, idd, company_name, company_email, roundrecord_id, cid) => {
        let formData = {
            investor_id: userLogin.id,
            company_investor_id: idd,
            company_name: company_name,
            company_email: company_email,
            company_id: company_id,
            investor_email: userLogin.email,
            ClientIP: ClientIP,
            CountryName: CountryName,
            user_id: userid,

        };

        try {
            const res = await axios.post(apiURL + "joinedcompany", formData, {
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",
                    'Authorization': `Bearer ${access_token}`,
                },
            });
            getInvitaionCompany();
            var company_id = cid;
            var id = roundrecord_id;
            setmessagesuccessError(`Successfully joined ${company_name}!`)
            setTimeout(() => {
                navigate(`/investor/company/company-round-list/view/${company_id}/${id || 0}`)
            }, 3500);
        } catch (err) { }
    };


    const filteredData = records?.filter((item) => {
        const search = searchText.toLowerCase();

        // Combine all searchable fields that ACTUALLY exist in your data
        const combinedFields = `
        ${item.company_name || ""}
        ${item.phone || ""}
        ${item.country || item.company_country || ""}
        ${item.city || item.company_city || ""}
        ${item.email || ""}
        ${item.investor_name || ""}
        ${item.first_name || ""}
        ${item.last_name || ""}
        ${item.nameOfRound || ""}
    `.toLowerCase();

        return combinedFields.includes(search);
    }) || [];
    //Chat Message
    const [selectedChatUser, setSelectedChatUser] = useState(null);
    const [showChatModal, setShowChatModal] = useState(false);
    var invname = userLogin?.first_name + " " + userLogin?.last_name;
    const currentUser = {
        id: userLogin.id,
        type: "investor",
        name: invname,
        email: userLogin.email,
    };
    const handlemessage = (corpid, name, email, logo) => {
        setSelectedChatUser({
            id: corpid,
            type: "company",
            name: name,
            role: "Company",
            avatar: logo
        });
        setShowChatModal(true);
    };
    const handleopenPopup = (id, roundrecord_id) => {
        setSelectedIds({ company_id: id, roundrecord_id });
        setPopupOpen(true);
    };
    const [fundingroundMessage, setfundingroundMessage] = useState("");
    const [corpId, setcorpId] = useState('');
    const [UserId, setUserId] = useState('');
    const [CompanyId, setCompanyId] = useState('');
    const [CompanyName, setCompanyName] = useState('');
    const [Companyemail, setCompanyemail] = useState('');
    const handleArchive = async (id, uid, corpid, cemail, cname) => {
        setcorpId(id);
        setfundingroundMessage("Are you sure you want to archive this?");
        setUserId(uid);
        setCompanyId(corpid);
        setCompanyName(cname);
        setCompanyemail(cemail);
    };
    const handlefundingRoundConfirm = async () => {

        try {
            const res = await axios.post(
                apiURLround + "archiveInvitation",
                {
                    company_investor_id_id: corpId,
                    investor_id: userLogin.id,
                    company_name: CompanyName,
                    company_email: Companyemail,
                    company_id: CompanyId,
                    ClientIP: ClientIP,
                    CountryName: CountryName,
                    user_id: UserId,
                },
                {
                    headers: {
                        Accept: "application/json",
                        "Content-Type": "application/json",
                        'Authorization': `Bearer ${access_token}`,
                    },
                }
            );
            if (res.data.status === '1') {
                setmessagesuccessError("Archived successfully.");
                seterrr(true);

                // ── REFRESH DATA ──
                // replace with your actual list refresh function
                getInvitaionCompany();
                setTimeout(() => {
                    getInvitaionCompany();
                    // window.location.reload();
                    setfundingroundMessage('')
                    setmessagesuccessError('');
                }, 3000);

            } else {
                setfundingroundMessage('')
                setmessagesuccessError(res.data.message || "Failed to archive invitation.");
                seterrr(false);
                setTimeout(() => {
                    getInvitaionCompany();

                    setfundingroundMessage('')
                    setmessagesuccessError('');
                }, 3000);
            }

        } catch (err) {
            setfundingroundMessage('')
            setmessagesuccessError("Something went wrong. Please try again.");
            seterrr(false);
        }
    }
    return (

        <>
            <main>
                <div className='d-flex align-items-start gap-0'>
                    <SideBar />
                    <div className='d-flex flex-grow-1 flex-column gap-0'>
                        <TopBar />
                        {fundingroundMessage && (
                            <DangerAlertPopup
                                message={fundingroundMessage}
                                onConfirm={handlefundingRoundConfirm}
                                onCancel={() => {
                                    setfundingroundMessage("");
                                }}
                            />
                        )}
                        <SectionWrapper className="d-block p-md-4 p-3">
                            <div className="container-fluid">
                                <DataRoomSection className="d-flex flex-column gap-3">
                                    <div className="titleroom flex-wrap  gap-3 d-flex justify-content-between align-items-center border-bottom pb-3">
                                        <h4 className="mainh1">Company List</h4>
                                    </div>
                                    {messagesuccessError && (
                                        <div
                                            className={`flex items-center justify-between gap-3 shadow-lg ${errr ? "error_pop" : "success_pop"
                                                }`}
                                        >
                                            <div className="d-flex align-items-center gap-2">
                                                <span className="d-block">{messagesuccessError}</span>
                                            </div>

                                            <button
                                                type="button"
                                                className="close_btnCros"
                                                onClick={() => setmessagesuccessError("")}
                                            >
                                                ×
                                            </button>
                                        </div>
                                    )}
                                    <div className="d-flex justify-content-end p-0">
                                        <input
                                            type="search"
                                            placeholder="Search Here..."
                                            className="textarea_input"
                                            value={searchText}
                                            onChange={(e) => setSearchText(e.target.value)}
                                            style={{
                                                padding: "10px",
                                                width: "100%",
                                                maxWidth: "200px",
                                                fontSize: "14px",
                                            }}
                                        />
                                    </div>
                                    <div className="d-flex  flex-column justify-content-between align-items-start tb-box">

                                        <DataTable
                                            customStyles={customStyles}
                                            columns={[
                                                {
                                                    name: "Company Name",
                                                    selector: (row) => row.company_name, // Changed from row.email
                                                    sortable: true,
                                                    cell: (row) => (
                                                        <div className="d-flex align-items-center">

                                                            <span>{row.company_name}</span>{" "}
                                                            {/* Changed from row.email */}
                                                        </div>
                                                    ),
                                                },
                                                {
                                                    name: "City",
                                                    selector: (row) => row.company_city, // Changed from company_email_match
                                                    sortable: true,
                                                    cell: (row) => (
                                                        <div className="d-flex align-items-center">

                                                            <span>{row.company_city}</span>{" "}
                                                            {/* Changed from company_email_match display */}
                                                        </div>
                                                    ),
                                                },
                                                {
                                                    name: "Sector",
                                                    selector: (row) => row.regulatory_compliance, // Changed from company_email_match
                                                    sortable: true,
                                                    cell: (row) => (
                                                        <div className="d-flex align-items-center">

                                                            <span>{row.regulatory_compliance}</span>
                                                        </div>
                                                    ),
                                                },
                                                {
                                                    name: "Funding Round",
                                                    selector: (row) => row.nameOfRound,
                                                    sortable: true,
                                                    cell: (row) => (
                                                        <div className="d-flex align-items-center">

                                                            <span>{row.nameOfRound || "N/A"}</span>
                                                        </div>
                                                    ),
                                                },
                                                {
                                                    name: "Company OverView",
                                                    sortable: true,
                                                    cell: (row) => (
                                                        <span style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>

                                                            <Link onClick={() => handleopenPopup(row.id, row.roundrecord_id)}
                                                                to="javascript:void(0)"

                                                                className="dropdown-item"
                                                                style={{
                                                                    display: "flex",
                                                                    alignItems: "center",
                                                                    gap: "8px",
                                                                    padding: "8px 16px",
                                                                    color: "#333",
                                                                    textDecoration: "none",
                                                                }}

                                                            >
                                                                <FaEye style={{ cursor: 'pointer', color: '#CC0000' }} />
                                                            </Link>
                                                        </span>
                                                    ),
                                                },
                                                {
                                                    name: "Actions",
                                                    cell: (row) => (
                                                        <div className="d-flex align-items-center gap-2">
                                                            {(row.joinstatus === 'No' || row.joinstatus === null || row.joinstatus === undefined || row.joinstatus === '') ? (
                                                                <>
                                                                    <button title="Accept"
                                                                        onClick={() => handlejoinCompany(row.user_id, row.company_id, row.company_investor_id, row.company_name, row.company_email, row.roundrecord_id, row.id)}
                                                                        style={{
                                                                            backgroundColor: '#CC0000',
                                                                            color: 'white',
                                                                            border: 'none',
                                                                            borderRadius: '6px',
                                                                            padding: '6px 12px',
                                                                            fontSize: '13px',
                                                                            fontWeight: '500',
                                                                            cursor: 'pointer',
                                                                            display: 'flex',
                                                                            alignItems: 'center',
                                                                            gap: '5px',
                                                                            whiteSpace: 'nowrap',
                                                                            transition: 'background 0.2s',
                                                                        }}
                                                                        onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#a00000'}
                                                                        onMouseLeave={(e) => e.currentTarget.style.backgroundColor = '#CC0000'}
                                                                    >
                                                                        <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                                                            <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14" />
                                                                            <polyline points="22 4 12 14.01 9 11.01" />
                                                                        </svg>

                                                                    </button>

                                                                </>

                                                            ) : row.joinstatus === 'Yes' ? (

                                                                <button title="Accepted"
                                                                    disabled
                                                                    style={{
                                                                        backgroundColor: '#28a745',
                                                                        color: 'white',
                                                                        border: 'none',
                                                                        borderRadius: '6px',
                                                                        padding: '6px 12px',
                                                                        fontSize: '13px',
                                                                        fontWeight: '500',
                                                                        cursor: 'default',
                                                                        display: 'flex',
                                                                        alignItems: 'center',
                                                                        gap: '5px',
                                                                        whiteSpace: 'nowrap',
                                                                        opacity: 1,
                                                                    }}
                                                                >
                                                                    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                                                        <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14" />
                                                                        <polyline points="22 4 12 14.01 9 11.01" />
                                                                    </svg>

                                                                </button>

                                                            ) : null}


                                                            <button title="Archive"
                                                                onClick={() => handleArchive(row.company_investor_id, row.user_id, row.company_id, row.company_email, row.company_name)}
                                                                style={{
                                                                    backgroundColor: '#CC0000',
                                                                    color: 'white',
                                                                    border: 'none',
                                                                    borderRadius: '6px',
                                                                    padding: '6px 12px',
                                                                    fontSize: '13px',
                                                                    fontWeight: '500',
                                                                    cursor: 'pointer',
                                                                    display: 'flex',
                                                                    alignItems: 'center',
                                                                    gap: '5px',
                                                                    whiteSpace: 'nowrap',
                                                                    transition: 'background 0.2s',
                                                                }}
                                                                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#CC0000'}
                                                                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = '#CC0000'}
                                                            >
                                                                {/* Archive Icon */}
                                                                <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                                                    <polyline points="21 8 21 21 3 21 3 8" />
                                                                    <rect x="1" y="3" width="22" height="5" />
                                                                    <line x1="10" y1="12" x2="14" y2="12" />
                                                                </svg>

                                                            </button>

                                                            {/* ── ARCHIVE BUTTON ── */}

                                                        </div>
                                                    ),
                                                    ignoreRowClick: true,
                                                    allowOverflow: true,
                                                    minWidth: '180px',
                                                },

                                            ]}
                                            className="datatb-report"
                                            data={filteredData}
                                            pagination
                                            highlightOnHover
                                            striped
                                            responsive
                                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                                            paginationComponentOptions={{
                                                rowsPerPageText: "Rows per page:",
                                                rangeSeparatorText: "of",
                                                noRowsPerPage: false,
                                                selectAllRowsItem: false,
                                            }}
                                        />
                                    </div>
                                </DataRoomSection>
                            </div>
                        </SectionWrapper>
                    </div>
                </div >
            </main >
            {showChatModal && selectedChatUser && (
                <ChatMessageModal
                    onClose={() => {
                        setShowChatModal(false);
                        setSelectedChatUser(null);
                    }}
                    currentUser={currentUser}
                    selectedUser={selectedChatUser}
                />
            )}
            {popupOpen && (
                <CapitalRoundViewCompanyInvite
                    id={selectedIds.id}
                    roundrecord_id={selectedIds.roundrecord_id}
                    onClose={() => setPopupOpen(false)}
                />
            )}
        </>
    );
}

export default CompanyInvitationList;
